                }
                group_items[g1].pop_back();

                if (i2 != back2) {
                    group_items[g2][pos2] = back2;
                    item_pos[back2] = pos2;
                }
                group_items[g2].pop_back();

                group_items[g2].push_back(i1);
                item_pos[i1] = group_items[g2].size() - 1;
                group_items[g1].push_back(i2);
                item_pos[i2] = group_items[g1].size() - 1;
            }
        } else {
            // Relocate move
            int item = rng() % N;
            int old_g = assignment[item];
            int new_g = rng() % D;
            while (new_g == old_g) new_g = rng() % D;

            double old_s_old = group_sums[old_g], old_s_new = group_sums[new_g];
            double new_s_old = old_s_old - weights[item];
            double new_s_new = old_s_new + weights[item];

            double new_sum_sq = sum_sq - old_s_old*old_s_old - old_s_new*old_s_new
