            double new_var = new_sum_sq / D - mean_sum * mean_sum;
            if (new_var < 0) new_var = 0;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng) < std::exp(-delta / T))) {
                sum_sq = new_sum_sq;
                current_var = new_var;
                group_sums[old_g] = new_s_old;
                group_sums[new_g] = new_s_new;
                assignment[item] = new_g;

                int pos = item_pos[item];
                int back = group_items[old_g].back();
                if (item != back) {
                    group_items[old_g][pos] = back;
                    item_pos[back] = pos;
                }
                group_items[old_g].pop_back();

                group_items[new_g].push_back(item);
                item_pos[item] = group_items[new_g].size() - 1;
            }
        }
    }

