#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <chrono>
#include <random>
#include <map>

std::chrono::steady_clock::time_point start_time;
const int TIME_LIMIT_MS = 1850;

int N, D, Q;
int queries_used = 0;
std::mt19937 rng;
std::map<std::pair<int,int>, char> cache;

bool time_ok() {
    auto now = std::chrono::steady_clock::now();
    return std::chrono::duration_cast<std::chrono::milliseconds>(now - start_time).count() < TIME_LIMIT_MS;
}

char raw_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_used++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << "\n" << std::flush;
    char c;
    std::cin >> c;
    return c;
}

char compare(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a,b), std::max(a,b));
    auto it = cache.find(key);
    if (it != cache.end()) {
        char c = it->second;
        return (a == key.first) ? c : (c == '<' ? '>' : (c == '>' ? '<' : '='));
    }
    if (queries_used >= Q) return '=';
    char res = raw_query({a}, {b});
    char store = (a < b) ? res : (res == '<' ? '>' : (res == '>' ? '<' : '='));
    cache[key] = store;
    return res;
}

void merge_sort_impl(std::vector<int>& arr, int l, int r) {
    if (l >= r) return;
    int m = (l + r) / 2;
    merge_sort_impl(arr, l, m);
    merge_sort_impl(arr, m+1, r);
    std::vector<int> tmp;
    tmp.reserve(r - l + 1);
    int i = l, j = m+1;
    while (i <= m && j <= r) {
        if (queries_used >= Q) {
            while (i <= m) tmp.push_back(arr[i++]);
            while (j <= r) tmp.push_back(arr[j++]);
            break;
        }
        char c = compare(arr[i], arr[j]);
        if (c == '<' || c == '=') tmp.push_back(arr[i++]);
        else tmp.push_back(arr[j++]);
    }
    while (i <= m) tmp.push_back(arr[i++]);
    while (j <= r) tmp.push_back(arr[j++]);
    for (int k = l; k <= r; k++) arr[k] = tmp[k-l];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    start_time = std::chrono::steady_clock::now();
    rng.seed(std::chrono::steady_clock::now().time_since_epoch().count());

    std::cin >> N >> D >> Q;

    // Phase 1: Sort all items using merge sort
    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);
    std::shuffle(sorted_items.begin(), sorted_items.end(), rng);
    merge_sort_impl(sorted_items, 0, N-1);

    // Phase 2: Assign initial weights from exponential order statistics
    const double inv_lambda = 100000.0;
    std::vector<double> weights(N);
    {
        double cumsum = 0.0;
        for (int i = 0; i < N; i++) {
            cumsum += 1.0 / (N - i);
            weights[sorted_items[i]] = std::max(1.0, inv_lambda * cumsum);
        }
    }

    // Phase 3: Calibrate weights using remaining queries
    // For each item i (from index 2 to N-1), determine:
    //   Is w[sorted[i]] > w[sorted[i-1]] + w[sorted[j]] for various j?
    // Binary search on j to find the tightest bound
    int remaining = Q - queries_used;

    if (remaining > 0 && N >= 3) {
        // For each item from 2..N-1, binary search among items 0..i-2
        // to find largest j such that sorted[i] > sorted[i-1] + sorted[j]
        // This gives: w[i] is between w[i-1]+w[j] and w[i-1]+w[j+1]

        // Budget allocation: distribute remaining queries across items
        int queries_per_item = std::max(1, remaining / (N - 2));

        for (int i = 2; i < N && queries_used < Q; i++) {
            int cur = sorted_items[i];
            int prev = sorted_items[i - 1];

            // Binary search: find largest j in [0, i-2] where cur > prev + sorted[j]
            int lo = 0, hi = i - 2;
            int best_j = -1;
            int budget = std::min(queries_per_item, (int)std::ceil(std::log2(i)));

            for (int iter = 0; iter < budget && lo <= hi && queries_used < Q; iter++) {
                int mid = (lo + hi) / 2;
                int aux = sorted_items[mid];
                // Query: {cur} vs {prev, aux}
                char res = raw_query({cur}, {prev, aux});

                if (res == '>') {
                    best_j = mid;
                    lo = mid + 1;
                } else if (res == '=') {
                    // cur == prev + aux
                    weights[cur] = weights[prev] + weights[aux];
                    best_j = -2;
                    break;
                } else {
                    // cur < prev + aux
                    hi = mid - 1;
                }
            }

            if (best_j == -2) {
                // Exact match, already set
            } else if (best_j >= 0 && best_j + 1 <= i - 2) {
                // cur is between (prev + sorted[best_j]) and (prev + sorted[best_j+1])
                double lower = weights[prev] + weights[sorted_items[best_j]];
                double upper = weights[prev] + weights[sorted_items[best_j + 1]];
                weights[cur] = (lower + upper) / 2.0;
            } else if (best_j == i - 2) {
                // cur > prev + sorted[i-2] (the 2nd heaviest before cur)
                // cur > prev + sorted[i-2], no upper bound from this search
                double lower = weights[prev] + weights[sorted_items[i - 2]];
                // Use order statistics as upper bound (already assigned)
                weights[cur] = std::max(weights[cur], lower * 1.1);
            } else if (best_j == -1 && hi >= 0) {
                // cur < prev + sorted[0], so gap is very small
                // w[cur] is between w[prev] and w[prev] + w[sorted[0]]
                double lower = weights[prev];
                double upper = weights[prev] + weights[sorted_items[0]];
                weights[cur] = (lower + upper) / 2.0;
            }
            // else: couldn't determine, keep order statistics estimate

            // Ensure monotonicity
            if (weights[cur] < weights[sorted_items[i - 1]])
                weights[cur] = weights[sorted_items[i - 1]];
        }
    }

    // Exhaust remaining queries
    while (queries_used < Q) {
        raw_query({0}, {1});
    }

    // Phase 4: Greedy assignment (largest-first to lightest group)
    std::vector<std::pair<double, int>> items_by_weight(N);
    for (int i = 0; i < N; i++) items_by_weight[i] = {-weights[i], i};
    std::sort(items_by_weight.begin(), items_by_weight.end());

    std::vector<int> assignment(N);
    std::vector<double> group_sums(D, 0.0);
    std::vector<std::vector<int>> group_items_vec(D);
    std::vector<int> item_pos(N);

