        int best = 0;
        for (int g = 1; g < D; g++) {
            if (group_sums[g] < group_sums[best]) best = g;
        }
        assignment[item] = best;
        group_sums[best] += weights[item];
        item_pos[item] = group_items_vec[best].size();
        group_items_vec[best].push_back(item);
    }

    // Phase 5: Simulated Annealing
    double total_sum = 0;
    for (int i = 0; i < N; i++) total_sum += weights[i];
    double mean_sum = total_sum / D;

    double sum_sq = 0;
    for (int g = 0; g < D; g++) sum_sq += group_sums[g] * group_sums[g];
    double current_var = sum_sq / D - mean_sum * mean_sum;
    if (current_var < 0) current_var = 0;

    double T = std::max(1.0, current_var * 0.25);
    if (current_var < 1e-9) T = std::max(1.0, total_sum / N * 0.1);

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    int iter = 0;

