            double new_s2 = old_s2 - weights[i2] + weights[i1];

            double new_sum_sq = sum_sq - old_s1*old_s1 - old_s2*old_s2 + new_s1*new_s1 + new_s2*new_s2;
            double new_var = new_sum_sq / D - mean_sum * mean_sum;
            if (new_var < 0) new_var = 0;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng) < std::exp(-delta / T))) {
                sum_sq = new_sum_sq;
                current_var = new_var;
                group_sums[g1] = new_s1;
                group_sums[g2] = new_s2;
                assignment[i1] = g2;
                assignment[i2] = g1;

                int pos1 = item_pos[i1], pos2 = item_pos[i2];
                int back1 = group_items_vec[g1].back();
                int back2 = group_items_vec[g2].back();

                if (i1 != back1) {
                    group_items_vec[g1][pos1] = back1;
                    item_pos[back1] = pos1;
                }
                group_items_vec[g1].pop_back();
                if (i2 != back2) {
                    group_items_vec[g2][pos2] = back2;
                    item_pos[back2] = pos2;
                }
                group_items_vec[g2].pop_back();

                group_items_vec[g2].push_back(i1);
                item_pos[i1] = group_items_vec[g2].size() - 1;
                group_items_vec[g1].push_back(i2);
                item_pos[i2] = group_items_vec[g1].size() - 1;
            }
        } else {
            int item = rng() % N;
            int old_g = assignment[item];
            int new_g = rng() % D;
            while (new_g == old_g) new_g = rng() % D;

            double old_s_old = group_sums[old_g], old_s_new = group_sums[new_g];
            double new_s_old = old_s_old - weights[item];
            double new_s_new = old_s_new + weights[item];

            double new_sum_sq = sum_sq - old_s_old*old_s_old - old_s_new*old_s_new
                              + new_s_old*new_s_old + new_s_new*new_s_new;
            double new_var = new_sum_sq / D - mean_sum * mean_sum;
            if (new_var < 0) new_var = 0;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng) < std::exp(-delta / T))) {
                sum_sq = new_sum_sq;
                current_var = new_var;
                group_sums[old_g] = new_s_old;
                group_sums[new_g] = new_s_new;
                assignment[item] = new_g;

                int pos = item_pos[item];
                int back = group_items_vec[old_g].back();
                if (item != back) {
                    group_items_vec[old_g][pos] = back;
                    item_pos[back] = pos;
                }
                group_items_vec[old_g].pop_back();
                group_items_vec[new_g].push_back(item);
                item_pos[item] = group_items_vec[new_g].size() - 1;
            }
        }
    }

    for (int i = 0; i < N; i++) {
        std::cout << assignment[i] << (i < N-1 ? " " : "");
    }
